"use strict";parserFactory.register("karistudio.com",()=>new KariStudioParser);class KariStudioParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("div.novel_index a")].map(e=>util.hyperLinkToChapter(e)).reverse()}findContent(e){return e.querySelector("article.small")}extractTitleImpl(e){return e.querySelector("h1")}findChapterTitle(e){return e.querySelector("h1").textContent}findCoverImageUrl(e){return util.getFirstImgSrc(e,"#novel_info_left")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.desc_div p")]}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,".confuse, #novel_nav, .post-rating-wrapper, #donation-msg, .clearfix, .navigation, #font-options-bar"),super.removeUnwantedElementsFromContentElement(e)}}